using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Placa de peso genérica (Etapa 6.1). Soma o peso de tudo o que está em cima
/// (trigger) e, quando atinge "requiredWeight" (configurável por placa), fica
/// pressionada — escrevendo numa variável global (GameVariables).
///
/// Todos os pesos são "de jogo" (não a massa física do Unity, que afectaria
/// knockback/colisões), por esta prioridade:
/// 1. ObjectWeight no objecto (override explícito — vence sempre);
/// 2. Player = peso da forma animal actual (AnimalFormData.weightMultiplier
///    via FormSwitcher; formas pesadas pressionam placas que leves não);
/// 3. Inimigo = EnemyData.stats.weight (apenas se 'canPressWeightPlate' —
///    Etapa 6.2: "peso necessário vs peso do inimigo");
/// 4. Outros Rigidbody2D = rb.mass (fallback, se 'useRigidbodyMassFallback').
/// </summary>
public class WeightPlate : MonoBehaviour
{
    [Header("Peso")]
    [Tooltip("Peso total mínimo em cima da placa para ela ficar pressionada (configurável por placa).")]
    [Min(0.01f)] public float requiredWeight = 1f;

    [Tooltip("Peso usado para o player se a forma actual não for encontrada (sem FormSwitcher/CurrentForm). Normalmente vem de AnimalFormData.weightMultiplier.")]
    [Min(0f)] public float playerFallbackWeight = 1f;

    [Tooltip("Objectos sem ObjectWeight usam Rigidbody2D.mass como peso. Desliga para só contar objectos com ObjectWeight explícito.")]
    public bool useRigidbodyMassFallback = true;

    [Header("Variável Global (GameVariables)")]
    [Tooltip("Nome da variável global escrita com o estado (true/1 = pressionada). Vazio = não escreve.")]
    public string variableName = "";

    [Tooltip("Se activo, escreve a variável como INT (1/0) em vez de BOOL.")]
    public bool writeAsInt = false;

    [Tooltip("Se activo, a placa fica presa em 'pressionada' na primeira activação (não volta a soltar).")]
    public bool latchOnce = false;

    [Header("Persistência após Morte / Saída de Área")]
    [Tooltip("GDD: puzzle persistente vs. de tentativa.\n\nPrimariamente útil com 'latchOnce': ao reentrar na cena, a placa restaura o estado de latch a partir de 'variableName' (GameVariables).\nSem 'latchOnce', a placa está sempre desactivada ao carregar (nada em cima) — persistState não tem efeito prático.\n\nLigado → restaura o estado da variável global ao Start.\nDesligado (padrão) → placa começa desactivada → puzzle reinicia.")]
    public bool persistState = false;

    [Header("Visual (opcional)")]
    public SpriteRenderer spriteRenderer;
    public Sprite spritePressed;
    public Sprite spriteReleased;

    [Header("Eventos")]
    public UnityEvent<bool> onPressedChanged;

    /// <summary>True enquanto o peso em cima da placa é &gt;= "requiredWeight".</summary>
    public bool IsPressed { get; private set; }

    /// <summary>Peso total actual em cima da placa.</summary>
    public float CurrentWeight { get; private set; }

    private readonly HashSet<Collider2D> _occupants = new HashSet<Collider2D>();

    private void Start()
    {
        if (persistState && !string.IsNullOrEmpty(variableName) && GameVariables.Instance != null)
        {
            bool saved = writeAsInt
                ? GameVariables.Instance.GetInt(variableName) != 0
                : GameVariables.Instance.GetBool(variableName);
            IsPressed = saved;
            ApplyVisual();
        }
        else
        {
            Apply();
        }
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (GetWeightOf(other) <= 0f) return;
        _occupants.Add(other);
        Recalculate();
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (_occupants.Remove(other))
            Recalculate();
    }

    private void Recalculate()
    {
        // Remove ocupantes destruídos/desactivados entretanto.
        _occupants.RemoveWhere(c => c == null || !c.gameObject.activeInHierarchy);

        float total = 0f;
        foreach (var occupant in _occupants)
            total += GetWeightOf(occupant);

        CurrentWeight = total;

        bool pressed = total >= requiredWeight;
        if (latchOnce && IsPressed) pressed = true;

        if (pressed == IsPressed) return;

        IsPressed = pressed;
        Apply();
        onPressedChanged?.Invoke(IsPressed);
    }

    /// <summary>Peso de um collider, pela prioridade descrita no cabeçalho: ObjectWeight > forma do player > stats.weight do inimigo > rb.mass (fallback) > 0. Ver GameWeightUtil (partilhado com SeesawPlatform/FloatingPlatform).</summary>
    private float GetWeightOf(Collider2D other) => GameWeightUtil.GetWeightOf(other, playerFallbackWeight, useRigidbodyMassFallback);

    private void Apply()
    {
        if (!string.IsNullOrEmpty(variableName) && GameVariables.Instance != null)
        {
            if (writeAsInt) GameVariables.Instance.SetInt(variableName, IsPressed ? 1 : 0);
            else GameVariables.Instance.SetBool(variableName, IsPressed);
        }

        ApplyVisual();
    }

    private void ApplyVisual()
    {
        if (spriteRenderer != null)
        {
            var sprite = IsPressed ? spritePressed : spriteReleased;
            if (sprite != null) spriteRenderer.sprite = sprite;
        }
    }
}
